    {"id": "beat-1", "text": "A user sits at a desk in a dimly lit room, a single lamp illuminating a computer screen displaying a traditional search engine's homepage."},
    {"id": "beat-2", "text": "The user types a long, complex question into the search bar, their expression concentrated and hopeful."},
    {"id": "beat-3", "text": "The search results page explodes with hundreds of blue links, text snippets, and ads, overwhelming the screen."},
    {"id": "beat-4", "text": "The user clicks on a result, and we see them scrolling frantically through a dense webpage, their eyes darting across lines of text."},
    {"id": "beat-5", "text": "The user slumps back in their chair, a frustrated sigh escaping as they rub their temples, the search still incomplete."}
  ]
}

